import{_ as e,o as s,c as a,a2 as o}from"./chunks/framework.BWuWLRhz.js";const n="/assets/29-team-structure@2x.Bb839tmn.png",u=JSON.parse('{"title":"29 · Agent teams 智能体团队：多会话协作","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/29-agent-teams.md","filePath":"claude-code/29-agent-teams.md"}'),d={name:"claude-code/29-agent-teams.md"};function r(p,t,g,l,i,c){return s(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="_29-·-agent-teams-智能体团队-多会话协作" tabindex="-1">29 · Agent teams 智能体团队：多会话协作 <a class="header-anchor" href="#_29-·-agent-teams-智能体团队-多会话协作" aria-label="Permalink to &quot;29 · Agent teams 智能体团队：多会话协作&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 [28 skill-creator 使用] 教你造一个能被准确触发的 skill。这一篇上「多智能体协作」——把好几个 Claude Code 会话编成一个团队，<strong>你当工头分活、它们各包一段并行干</strong>，干完你统一验收。</p></blockquote><blockquote><p>⚠️ <strong>实验性，可能变化</strong>：Agent teams 是官方明确标注的实验性功能，<strong>默认关闭</strong>，需要 Claude Code v2.1.32 或更高版本。本篇命令和默认值以写作时的官方文档为准，但界面、快捷键、行为后续都可能调整，照做前先 <code>claude --version</code> 对一下版本。</p></blockquote><p>「你这屏幕上怎么开着仨 Claude？还都在跑。」</p><p>「一个在改前端、一个改后端、一个专门写测试，我盯着分活。」</p><p>「那不乱套了？你一个人哪盯得过来三个？」</p><p>「不用我一直盯。它们各干各的，谁卡住了、谁要我拍板，会主动冒泡找我——我大部分时间在干别的。」</p><p>这段对话里那个开着仨 Claude 的人，就是我。我自己第一次同屏跑多个会话那会儿，旁边同事的反应一模一样——先是惊，再是「你盯得过来吗」。说白了，<strong>让人惊讶的点全在「一个人怎么同时指挥多个 AI」</strong>，而这正是这一篇要拆的东西——Agent teams（智能体团队），让多个 Claude Code 会话像一个团队那样协作，你只负责分派和验收。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>Agent teams 到底是什么、解决单会话的什么天花板，一句话讲透</li><li>它和上一波学的 subagent（子代理）差在哪——一张对照表分清「啥时候用哪个」</li><li>团队的四个关键件（leader（负责人）、队友、共享任务列表、信箱）各干什么</li><li>怎么用 <code>claude agents</code>（agent view）这块「总控屏」管多个会话，以及在团队里 <code>Shift+Down</code> 切队友</li><li>一个能照着跑、给了预期输出的实战：启用功能 → 起一个三人团队 → 看它们并行干</li></ul><hr><h2 id="_01-先搞懂-单会话的天花板在哪" tabindex="-1">01 先搞懂：单会话的天花板在哪 <a class="header-anchor" href="#_01-先搞懂-单会话的天花板在哪" aria-label="Permalink to &quot;01 先搞懂：单会话的天花板在哪&quot;">​</a></h2><p>先给结论：<strong>Agent teams 是为了突破单个 Claude Code 会话「上下文有限 + 只能串行」这两堵墙</strong>。</p><p>前面十几篇我们一直在「一个会话」里折腾——开一个 Claude，给它指令，它一步步干。这模式 90% 的活儿够用。但有两种情况会顶到天花板：</p><p><strong>一是上下文塞不下。</strong> 一个会话只有一个上下文窗口（context window，可以理解成它的「工作记忆」）。让它同时读前端、后端、测试三大块代码再统筹改，记忆很快就满了，越往后它越「忘事」。</p><p><strong>二是只能一件接一件干。</strong> 单会话本质是串行的——读完 A 才读 B，改完前端才轮到后端。三块互不相干的活，它也只能排队来。</p><p><strong>类比：一个大工程，你一个人既当水电工、又当瓦工、还兼木工，全部工种自己上。</strong> 一是脑子里记不下这么多并行的事，盯着水电就忘了瓦工那边的进度；二是只有一双手，这会儿在接线就贴不了瓷砖，只能一个工种干完再换下一个。<strong>这时候聪明的做法不是自己硬扛，是当工头——招几个师傅，水电、瓦工、木工各包一段同时开干，你负责分活和验收。</strong></p><p>Agent teams 就是把你从「亲自下场的工人」变成「指挥若定的工头」。它适用在四类活儿上（官方点名的「最强用例」）：</p><ul><li><strong>研究和审查</strong>：几个队友同时查一个问题的不同侧面，再互相质疑彼此的发现</li><li><strong>新模块 / 新功能</strong>：每个队友独占一块互不干扰的部分</li><li><strong>使用竞争假设调试</strong>：几个队友并行测试不同理论，互相证伪，更快收敛到根因</li><li><strong>跨层改动</strong>：前端、后端、测试横跨多层，每层派一个队友盯</li></ul><blockquote><p>💡 一句话总结：单会话有「记忆装不下、活儿只能串行」两堵墙；<strong>Agent teams 让你从一个人硬扛，升级成工头带一队人并行干</strong>。</p></blockquote><hr><h2 id="_02-它和-subagent-到底差在哪" tabindex="-1">02 它和 subagent 到底差在哪 <a class="header-anchor" href="#_02-它和-subagent-到底差在哪" aria-label="Permalink to &quot;02 它和 subagent 到底差在哪&quot;">​</a></h2><p>这是最容易混的一对，必须先掰清楚——不然你学了俩功能也不知道该用哪个。</p><p>上一波（第 23 篇）我们学的 subagent，是<strong>在一个会话里</strong>外包一个专项助手：它有独立上下文，干完只把结论交回给主对话，<strong>队友之间互不说话、也不归你直接管</strong>。Agent teams 完全不是一回事——<strong>它是多个对等的、完整的 Claude Code 会话在协作</strong>，队友之间能直接发消息，你也能绕过 leader 直接跟某个队友聊。</p><p><strong>类比：subagent 是你派出去跑个腿的临时工，agent team 是你召集起来开工的一个班组。</strong> 跑腿的临时工，你交代一句「去把这一千行日志里的报错挑出来」，他自己去办、办完回来递张纸条，<strong>他不认识你别的临时工，全程只跟你这一个上级对接</strong>；而一个班组里的工人，彼此能商量「你那边的接口改了没、我这边好对接」，你这个工头也能随时走到任何一个工人跟前单独叮嘱几句。</p><p>差别落到实处，就是这张表——<strong>记不住别的就记它</strong>：</p><table tabindex="0"><thead><tr><th>维度</th><th>Subagent（子代理）</th><th>Agent teams（智能体团队）</th></tr></thead><tbody><tr><td><strong>上下文</strong></td><td>独立上下文，结果回传给调用者</td><td>独立上下文，<strong>完全独立</strong></td></tr><tr><td><strong>谁在协调</strong></td><td>主代理统管所有活</td><td>leader 协调，但有<strong>共享任务列表自我协调</strong></td></tr><tr><td><strong>队友之间</strong></td><td>不通信，只向主代理报结果</td><td><strong>直接互发消息</strong></td></tr><tr><td><strong>你能否直接管</strong></td><td>不能，只能通过主对话</td><td><strong>能直接跟任意队友对话</strong></td></tr><tr><td><strong>token 成本</strong></td><td>较低，结果汇总回主上下文</td><td><strong>较高，每个队友都是一个独立 Claude 实例</strong></td></tr><tr><td><strong>最适合</strong></td><td>只要结果、不用讨论的专注任务</td><td>需要讨论、互相质疑的复杂协作</td></tr></tbody></table><p>最该记住的一句官方判断标准：</p><blockquote><p>当你需要快速、专注的工作人员报告结果时，使用 subagents。当队友需要分享发现、相互质疑和自我协调时，使用 agent teams。</p></blockquote><p>还有个更直接的土办法：<strong>这帮「工人」之间需不需要互相通气？</strong> 不需要（各查各的、查完汇总），用 subagent，便宜；需要（边干边对接、互相挑刺），才上 agent teams。</p><blockquote><p>💡 一句话总结：subagent 是跑腿临时工——独立干、只对你一个人报；agent teams 是一个班组——队友互相说话、你能直接管每一个；<strong>要不要互相通气，就是选哪个的分水岭</strong>。</p></blockquote><hr><h2 id="_03-团队是怎么搭起来的-四个关键件" tabindex="-1">03 团队是怎么搭起来的：四个关键件 <a class="header-anchor" href="#_03-团队是怎么搭起来的-四个关键件" aria-label="Permalink to &quot;03 团队是怎么搭起来的：四个关键件&quot;">​</a></h2><p>一个 agent team 跑起来，背后就四个零件。认住它们，你才看得懂屏幕上发生了什么。</p><p><strong>类比：一个真实的施工班组。</strong> 有一个工头（leader），有几个干活的工人（teammates），墙上贴着一张写满活儿的任务板（task list），工人之间还能互相递条子沟通（mailbox 信箱）。这四样凑齐，班组就能转。</p><p>官方给的架构表，就是这四件：</p><table tabindex="0"><thead><tr><th>组件</th><th>角色</th></tr></thead><tbody><tr><td><strong>Team lead（负责人）</strong></td><td>创建团队、生成队友、协调分活的那个主会话——就是你最先打开的那个</td></tr><tr><td><strong>Teammates（队友）</strong></td><td>各自领任务干活的独立 Claude Code 实例，每个有自己的上下文</td></tr><tr><td><strong>Task list（任务列表）</strong></td><td>队友认领和完成的共享工作清单，三种状态：待处理 / 进行中 / 已完成</td></tr><tr><td><strong>Mailbox（信箱）</strong></td><td>代理之间互发消息的系统，队友的消息会自动送到 leader，不用你去轮询</td></tr></tbody></table><p>几个新手最该知道的运转细节：</p><p><strong>leader 一旦定了就换不了。</strong> 创建团队的那个会话，终其一生都是 leader——你没法把某个队友「提拔」成 leader，也不能转交领导权。所以<strong>你最先打开的那个会话，就是你这个「工头」的本体</strong>。</p><p><strong>队友领活有两种方式。</strong> leader 可以明着指派「这个任务给小 A」；队友也可以干完手头的活，自己从任务板上挑下一个没人认领、没被卡住的任务接着干（官方叫「自我认领」）。为了防止俩队友同时抢同一个任务，系统用<strong>文件锁</strong>兜底，不会撞车。</p><p><strong>任务之间能有依赖。</strong> 比如「写测试」得等「实现功能」先完成。有未完成依赖的任务，在依赖没干完前认领不了；依赖一旦完成，被卡住的任务会<strong>自动解锁</strong>。</p><p><strong>队友不继承你的对话历史。</strong> 这点新手最容易栽——想当然以为 leader 知道的事队友自然都知道，结果生成队友时啥背景都没给，它一脸懵。官方写得很清楚：队友生成时会加载和常规会话一样的项目上下文（<code>CLAUDE.md</code>、MCP、skills），<strong>但 leader 的对话历史不会继承</strong>。所以派活时，该交代的背景得在指令里写明白。</p><blockquote><p>💡 一句话总结：一个团队 = 工头（leader，定了不能换）+ 工人（队友，各有独立上下文）+ 任务板（共享列表，能依赖、能自我认领）+ 信箱（互发消息）；<strong>派活时记得把背景写全，队友不读你的历史</strong>。</p></blockquote><p><img src="'+n+`" alt="Agent teams 团队结构：工头分活、队友并行、任务板协调、信箱互通"></p><p>这张图把一个 agent team 的四个零件摆清楚了：中间是你这个 leader（工头），向下生成几个独立的队友（工人）各包一块活；底下一张共享任务板让大家认领任务、自动处理依赖；队友之间还有信箱直连——<strong>消息绕不绕过 leader、活儿谁认领，一眼看明白</strong>。</p><hr><h2 id="_04-用-agent-view-当「总控屏」管多个会话" tabindex="-1">04 用 agent view 当「总控屏」管多个会话 <a class="header-anchor" href="#_04-用-agent-view-当「总控屏」管多个会话" aria-label="Permalink to &quot;04 用 agent view 当「总控屏」管多个会话&quot;">​</a></h2><p>团队起来了，问题来了：<strong>好几个会话同时在跑，我盯哪儿？</strong></p><p>答案是 agent view（代理视图）——一块把所有后台会话摊在一个屏幕上的「总控屏」，命令是 <code>claude agents</code>。</p><blockquote><p>⚠️ agent view 是<strong>研究预览版</strong>，需要 Claude Code v2.1.139 或更高版本，界面和快捷键可能随版本变。</p></blockquote><p><strong>类比：施工现场墙上那块工程进度看板。</strong> 你不用挨个工位去问「干到哪了」，抬头扫一眼看板就行——哪道工序在进行、哪个卡住等你拍板、哪个已经验收完了，一目了然。<code>claude agents</code> 就是 Claude Code 的这块看板：每个会话占一行，行首一个图标用颜色和动画告诉你它的状态。</p><p>官方的状态对照，挑最常用的几个：</p><table tabindex="0"><thead><tr><th>状态</th><th>图标显示</th><th>含义</th></tr></thead><tbody><tr><td>工作中</td><td>动画</td><td>Claude 正在跑工具或生成回复</td></tr><tr><td>需要输入</td><td>黄色</td><td>在等你回答某个问题或拍板某个权限</td></tr><tr><td>已完成</td><td>绿色</td><td>任务成功干完了</td></tr><tr><td>失败</td><td>红色</td><td>任务报错结束了</td></tr></tbody></table><p>在这块看板上，你对着任意一行能干三件事，由轻到重：</p><ul><li><strong>窥视（Peek）</strong>：按 <code>Space</code> 打开一个小面板，看这个会话最近的输出、或它正卡在哪个问题上——大多数时候这就够了，<strong>不用真进去</strong>。在窥视面板里直接打字回复、按 <code>Enter</code> 发出去，也不用进去。</li><li><strong>回复</strong>：窥视面板里就能回。它要是抛了个多选题，按数字键就能选。</li><li><strong>附加（Attach）</strong>：按 <code>Enter</code> 或 <code>→</code> 钻进这个会话的完整对话，就跟你平时单开一个 Claude 一模一样。在空输入框上按 <code>←</code> 退出来回看板。</li></ul><p>有个特别方便的设计：<strong>这些后台会话不需要任何终端开着也照跑</strong>。一个独立的监督进程（supervisor）在背后托管它们——你关掉 agent view、关掉这个 shell、甚至另开一个新会话，它们都在继续干。等你回来打开 <code>claude agents</code>，它们还在那儿。</p><p>你完全可以把 <code>claude agents</code> 当<strong>主入口</strong>用，而不是 <code>claude</code>：进来先在看板底部的输入框甩几个独立任务（每打一个提示按 <code>Enter</code> 就起一个新会话并行跑），然后该干嘛干嘛，哪行变黄了（需要你）或变绿了（干完了）再回来处理。<strong>比开七八个终端窗口来回切清爽太多了。</strong></p><blockquote><p>💡 一句话总结：<code>claude agents</code> 是管多会话的「总控屏」——一行一个会话、看颜色知状态；<code>Space</code> 窥视、<code>Enter</code> 钻进去、<code>←</code> 退出来；<strong>会话在后台照跑，不用一直开着终端盯</strong>。</p></blockquote><hr><h2 id="_05-在团队里指挥队友-分活、切人、要计划" tabindex="-1">05 在团队里指挥队友：分活、切人、要计划 <a class="header-anchor" href="#_05-在团队里指挥队友-分活、切人、要计划" aria-label="Permalink to &quot;05 在团队里指挥队友：分活、切人、要计划&quot;">​</a></h2><p>前面是「多会话」的通用管法。回到 agent teams 本身，<strong>你作为 leader 怎么具体指挥这帮队友</strong>？核心就一句：<strong>用大白话告诉 leader 你想要啥，它替你处理协调、分活、委派</strong>。</p><p><strong>起一个团队</strong>，不用记什么命令，自然语言描述任务和团队结构就行。官方那个效果很好的例子（三个角色互相独立、不用互相等）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I&#39;m designing a CLI tool that helps developers track TODO comments across</span></span>
<span class="line"><span>their codebase. Create an agent team to explore this from different angles: one</span></span>
<span class="line"><span>teammate on UX, one on technical architecture, one playing devil&#39;s advocate.</span></span></code></pre></div><p>翻成中文你也可以直接说：「帮我建一个 agent team 从不同角度探索这个问题：一个负责 UX、一个负责技术架构、一个专门唱反调。」Claude 就会创建团队、按角度生成队友、让它们各自探索、最后综合发现。</p><p><strong>切队友、单独叮嘱。</strong> 在 in-process（同终端内）模式下，按 <strong><code>Shift+Down</code></strong> 在队友之间循环，转到某个队友就能直接打字给他发消息——补个指令、追个问、或者让他换个思路。按 <code>Enter</code> 进他的会话看详情，<code>Escape</code> 打断他当前这一轮，<code>Ctrl+T</code> 切换任务列表。<strong>转到最后一个队友后再按 <code>Shift+Down</code>，会绕回 leader。</strong></p><blockquote><p>注意这里和上一节的快捷键别记串了：管后台会话的总控屏里切行用 <code>↑</code>/<code>↓</code>，而 agent team 里切队友用 <code>Shift+Down</code>，两套场景两套键。</p></blockquote><p><strong>让队友先出计划再动手。</strong> 活儿有风险时，可以要求队友在只读计划模式下先规划，等你（leader）批准了再实施：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>生成一个架构师队友来重构认证模块。</span></span>
<span class="line"><span>在他改动任何东西之前，必须先经过计划批准。</span></span></code></pre></div><p>队友规划完会给 leader 发一个「计划批准请求」，你批了它才退出计划模式开干；你打回去，它就照反馈改了重交。</p><p><strong>指定队友数量和模型。</strong> 你也可以明说要几个、用什么模型：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>建一个有 4 个队友的团队，并行重构这些模块。</span></span>
<span class="line"><span>每个队友都用 Sonnet。</span></span></code></pre></div><p>一个<strong>省钱关键点</strong>别忽略：队友默认<strong>不跟随</strong> leader 的 <code>/model</code> 选择。想统一改它们的模型，要么在提示里像上面那样指定，要么去 <code>/config</code> 设「默认队友模型」。</p><p><strong>干完收摊。</strong> 活儿结束，让 leader 清理团队：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>清理这个团队</span></span></code></pre></div><blockquote><p>⚠️ 官方反复强调：<strong>清理一定走 leader，别让队友去清理</strong>——队友的团队上下文可能解析不对，会把资源弄成不一致状态。而且清理前得先把还在跑的队友关掉，不然 leader 检测到有活跃队友会清理失败。</p></blockquote><blockquote><p>💡 一句话总结：起团队、分活、切队友（<code>Shift+Down</code>）、要计划批准、收摊清理，全用大白话指挥 leader；<strong>记牢三条——队友模型要单独指定、背景要在指令里给全、清理只走 leader</strong>。</p></blockquote><hr><h2 id="_06-该不该上团队-别为了拆而拆" tabindex="-1">06 该不该上团队：别为了拆而拆 <a class="header-anchor" href="#_06-该不该上团队-别为了拆而拆" aria-label="Permalink to &quot;06 该不该上团队：别为了拆而拆&quot;">​</a></h2><p>学到这儿你可能跃跃欲试，想把啥都拆成团队跑。<strong>打住——这正是第 23 篇讲 subagent 时那条反共识铁律的延续：不是任务越多越该拆。</strong></p><p>Agent teams 有实打实的代价，而且比 subagent 更重：</p><p><strong>一是 token 烧得多。</strong> 每个队友都是一个完整独立的 Claude 实例、各有各的上下文，<strong>几个队友就是几份 token 在烧</strong>。官方说得直白：日常任务，单会话更划算；只有研究、审查、新功能这类真能从并行获益的活，多花的 token 才值。</p><p><strong>二是协调本身有开销。</strong> 队友越多，互相通信、任务协调、潜在冲突就越多，过了某个点<strong>再加人也不会按比例提速</strong>——三个专注的队友常常干得过五个分散的队友。</p><p>我把「值不值得拆」整理成一张对照，照着对号入座：</p><table tabindex="0"><thead><tr><th>场景</th><th>拆不拆成团队</th></tr></thead><tbody><tr><td>前端 / 后端 / 测试三层并行改，互不依赖</td><td>✅ 拆，各包一层正合适</td></tr><tr><td>一个 bug 根因不明，想用几个竞争假设并行排查</td><td>✅ 拆，让队友互相证伪收敛更快</td></tr><tr><td>多人并行审一个 PR（安全 / 性能 / 测试覆盖各一人）</td><td>✅ 拆，各用一套过滤器不重叠</td></tr><tr><td>一连串有先后依赖的步骤（A 做完才能做 B）</td><td>❌ 别拆，串行的活单会话更顺</td></tr><tr><td>几个队友要改<strong>同一个文件</strong></td><td>❌ 别拆，两人编辑同一文件会互相覆盖</td></tr><tr><td>随手一个小任务</td><td>❌ 别拆，协调开销比省下的时间还多</td></tr></tbody></table><p>官方还给了两条特别实在的上手建议，新手照做能少踩坑：</p><p><strong>从「研究 / 审查」这类不写代码的活开始。</strong> 审 PR、调研一个库、排查 bug——这些任务边界清楚、不写代码，<strong>能让你体会并行探索的价值，又不带来并行写代码那一堆协调麻烦</strong>。我自己第一次用 agent teams，就是拿来审一个 PR：三个队友分别盯安全、性能、测试覆盖，全程没人改文件，自然也没冲突，看着三块发现陆续冒出来挺爽——体验顺了，我才敢往「并行改代码」上推。<strong>别像我后来那回，头脑一热直接让仨队友并行改三个相邻文件，结果改动互相打架，光理这堆冲突就比单会话老老实实串行干还慢。</strong></p><p><strong>团队规模从 3–5 个起步。</strong> 这个区间在各类任务上都好使——并行有了，协调又不至于失控。真要扩，只在「活儿确实能从更多人同时干获益」时才扩。</p><blockquote><p>💡 一句话总结：Agent teams 比 subagent 更烧 token、协调更重，<strong>只在「真能并行获益」时才拆</strong>；互相依赖、改同一文件、随手小活一律别拆；新手从「不写代码的研究 / 审查」+「3–5 人」起步最稳。</p></blockquote><hr><h2 id="_07-动手-启用功能-起一个三人团队跑起来" tabindex="-1">07 动手：启用功能，起一个三人团队跑起来 <a class="header-anchor" href="#_07-动手-启用功能-起一个三人团队跑起来" aria-label="Permalink to &quot;07 动手：启用功能，起一个三人团队跑起来&quot;">​</a></h2><p>光看不练假把式。下面带你<strong>从零启用 Agent teams，起一个三人团队并行干一件最简单的活</strong>。全程不依赖任何复杂项目。</p><blockquote><p>前提：<code>claude --version</code> 看一眼，得是 <strong>v2.1.32 或更高</strong>；不够就先 <code>claude update</code>。</p></blockquote><p><strong>第一步：启用实验性功能</strong></p><p>Agent teams 默认关闭，先在用户级设置里把开关打开。编辑 <code>~/.claude/settings.json</code>（没有就新建），加上 <code>env</code> 这段：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>预期</strong>：文件里有这段 <code>env</code> 配置。这是官方指定的启用方式——把环境变量 <code>CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS</code> 设成 <code>1</code>。</p><p><strong>第二步：建一个玩具目录并进去开 Claude</strong>(Mac / Linux)</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> team-demo</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> team-demo</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p>Windows 用户：<code>mkdir</code>、<code>cd</code> 照敲，再 <code>claude</code>。</p><p><strong>预期</strong>：出现 Claude Code 欢迎屏，底部有输入框。</p><p><strong>第三步：用大白话起一个三人团队</strong></p><p>在输入框里敲（这就是「描述任务 + 团队结构」让 leader 自己组队）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我建一个 agent team，从三个不同角度调研「个人博客该选静态站还是动态站」：</span></span>
<span class="line"><span>一个队友只论证「该选静态站」，一个只论证「该选动态站」，</span></span>
<span class="line"><span>一个唱反调专门挑前两个方案的毛病。让他们各自给出结论。</span></span></code></pre></div><p><strong>预期</strong>：Claude 会先告诉你它要创建一个团队、生成三个队友（各自一个角度），并请你确认。<strong>它不会不打招呼就建团队</strong>——官方明确「没有你的批准不会创建团队」。确认后，三个队友陆续起来，各自在自己的上下文里开干。</p><p><strong>第四步：用 <code>Shift+Down</code> 切到某个队友看看</strong></p><p>team 跑起来后，leader 的终端会列出所有队友和他们在干的活。按 <strong><code>Shift+Down</code></strong> 循环切到某个队友，你能直接给他发消息。比如切到「唱反调」那个，补一句：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>也帮我从「维护成本」这个角度再挑挑毛病</span></span></code></pre></div><p><strong>预期</strong>：这条消息直达那个队友（不经过 leader 转述），他会把「维护成本」也纳进来接着挑。<strong>切到最后一个队友再按 <code>Shift+Down</code>，会绕回 leader</strong>——回到 leader 你就又能统筹全局了。</p><p><strong>第五步：收摊清理</strong></p><p>调研完了，回到 leader，让它收摊：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我清理这个团队</span></span></code></pre></div><p><strong>预期</strong>：leader 会先确认队友都停了，再删掉共享的团队资源。<strong>如果还有队友在跑，清理会失败</strong>——这时先让 leader 把队友关掉（「让那几个队友 shut down」）再清理。记住官方那条：<strong>清理永远走 leader，别让队友去清。</strong></p><p>跑通这五步，你就把「启用 → 组队 → 并行干 → 切队友直聊 → 收摊」这条完整链路亲手走了一遍。<strong>之后任何 agent teams 的用法，本质都是在这条链路上换任务、换队友角色而已。</strong></p><blockquote><p>💡 一句话总结：<code>settings.json</code> 里 <code>env</code> 开开关 → 大白话让 leader 组队 → <code>Shift+Down</code> 切队友直聊 → leader 收摊清理；<strong>亲手跑通这条链路，比记十条快捷键都管用</strong>。</p></blockquote><hr><h2 id="_08-小结" tabindex="-1">08 小结 <a class="header-anchor" href="#_08-小结" aria-label="Permalink to &quot;08 小结&quot;">​</a></h2><p>这一篇我们把 Claude Code 的「多智能体协作」从头捋了一遍——<strong>你从一个亲自下场的工人，升级成了指挥一个班组的工头</strong>。</p><p>把核心要点串起来回顾：</p><table tabindex="0"><thead><tr><th>你想做的事</th><th>用什么</th><th>关键点</th></tr></thead><tbody><tr><td>突破单会话的记忆 + 串行天花板</td><td>Agent teams</td><td>多个对等会话并行，你当 leader 分活</td></tr><tr><td>分清和 subagent 的区别</td><td>看「要不要互相通气」</td><td>要通气、要互相质疑才用 team，否则 subagent 更省</td></tr><tr><td>管多个并行会话</td><td><code>claude agents</code>(agent view)</td><td>一行一会话、看颜色知状态、<code>Space</code> 窥视</td></tr><tr><td>在团队里切队友直聊</td><td><code>Shift+Down</code></td><td>转一圈回到 leader；和看板切行的 <code>↑</code>/<code>↓</code> 别记串</td></tr><tr><td>判断该不该拆</td><td>一张「值不值得」对照表</td><td>互相依赖、改同一文件、小活一律别拆</td></tr></tbody></table><p><strong>你现在应该能：</strong> 说清 Agent teams 解决什么、它和 subagent 差在哪、用 <code>claude agents</code> 这块总控屏盯住多个并行会话、用大白话指挥 leader 组队分活、并且清楚「什么时候值得拆、什么时候别为了拆而拆」。<strong>这套「当工头」的能力，是你把大任务真正并行化、又不至于烧钱失控的底气。</strong></p><p>但说句实话——<strong>它毕竟还是实验性的</strong>，界面、快捷键随版本变，日常 90% 的活儿单会话依旧够用。把它当个「大活儿提速神器」收进工具箱，别一上来就拿小任务硬拆。</p><hr><p>下一篇 <strong>30「功能怎么选：CLAUDE.md vs Skill vs Hook vs MCP vs Subagent」</strong>——到这篇为止，<code>CLAUDE.md</code>、Skill、Hook、MCP、Subagent、Agent teams，Claude Code 的招式你已经学了一大摞。但学得多不等于用得对，真正难的是临到一个具体需求，<strong>到底该掏哪一个？</strong> 下一篇我给你一张决策表，把这些功能的「适用边界」摆到一张纸上——看完你就再不会对着一个需求犯「该用啥」的选择困难症了。</p>`,123)])])}const b=e(d,[["render",r]]);export{u as __pageData,b as default};
